const $ = (id) => document.getElementById(id);
const fmtNumber = new Intl.NumberFormat("en-US");
const fmtCurrency = new Intl.NumberFormat("en-US", { style: "currency", currency: "USD", maximumFractionDigits: 0 });

const state = {
  department: "All",
  jobRole: "All",
  gender: "All",
  overtime: "All"
};

function isAttrition(row) {
  return String(row.Attrition).toLowerCase() === "yes";
}

function rate(rows) {
  if (!rows.length) return 0;
  return rows.filter(isAttrition).length / rows.length * 100;
}

function average(rows, key) {
  if (!rows.length) return 0;
  return rows.reduce((sum, row) => sum + Number(row[key] || 0), 0) / rows.length;
}

function uniqueValues(key) {
  return [...new Set(HR_DATA.map(row => row[key]).filter(Boolean))].sort((a, b) => String(a).localeCompare(String(b)));
}

function fillSelect(id, values, allLabel) {
  const select = $(id);
  select.innerHTML = `<option value="All">${allLabel}</option>` + values.map(value => `<option value="${escapeHtml(value)}">${escapeHtml(value)}</option>`).join("");
}

function escapeHtml(value) {
  return String(value).replace(/[&<>'"]/g, char => ({"&":"&amp;","<":"&lt;",">":"&gt;","'":"&#39;",'"':"&quot;"}[char]));
}

function getFilteredRows() {
  return HR_DATA.filter(row => {
    return (state.department === "All" || row.Department === state.department) &&
           (state.jobRole === "All" || row.JobRole === state.jobRole) &&
           (state.gender === "All" || row.Gender === state.gender) &&
           (state.overtime === "All" || row.OverTime === state.overtime);
  });
}

function groupBy(rows, keyFn, options = {}) {
  const minTotal = options.minTotal ?? 1;
  const order = options.order ?? null;
  const map = new Map();
  rows.forEach(row => {
    const key = typeof keyFn === "function" ? keyFn(row) : row[keyFn];
    if (!key) return;
    if (!map.has(key)) map.set(key, { label: key, total: 0, attrition: 0, income: 0 });
    const item = map.get(key);
    item.total += 1;
    item.attrition += isAttrition(row) ? 1 : 0;
    item.income += Number(row.MonthlyIncome || 0);
  });

  let items = [...map.values()]
    .filter(item => item.total >= minTotal)
    .map(item => ({
      ...item,
      rate: item.total ? item.attrition / item.total * 100 : 0,
      avgIncome: item.total ? item.income / item.total : 0
    }));

  if (order) {
    const orderMap = new Map(order.map((label, index) => [label, index]));
    items.sort((a, b) => (orderMap.get(a.label) ?? 999) - (orderMap.get(b.label) ?? 999));
  } else {
    items.sort((a, b) => b.rate - a.rate || b.total - a.total || a.label.localeCompare(b.label));
  }
  return items;
}

function ageGroup(row) {
  const age = Number(row.Age || 0);
  if (age < 30) return "< 30";
  if (age < 40) return "30–39";
  if (age < 50) return "40–49";
  return "50+";
}

function tenureGroup(row) {
  const years = Number(row.YearsAtCompany || 0);
  if (years <= 2) return "0–2 years";
  if (years <= 5) return "3–5 years";
  if (years <= 10) return "6–10 years";
  return "> 10 years";
}

function incomeGroup(row) {
  const income = Number(row.MonthlyIncome || 0);
  if (income < 3000) return "< $3K";
  if (income < 5000) return "$3K–$4.9K";
  if (income < 8000) return "$5K–$7.9K";
  if (income < 12000) return "$8K–$11.9K";
  return "$12K+";
}

function worklifeGroup(row) {
  const score = Number(row.WorkLifeBalance || 0);
  const labels = {1: "1 — Low", 2: "2 — Fair", 3: "3 — Good", 4: "4 — Excellent"};
  return labels[score] || "Unknown";
}

function renderBars(containerId, items, options = {}) {
  const container = $(containerId);
  if (!container) return;
  if (!items.length) {
    container.innerHTML = `<div class="no-data">No data available for this selected segment.</div>`;
    return;
  }

  const maxRate = Math.max(...items.map(item => item.rate), 1);
  const scaleMax = options.scaleTo100 ? 100 : maxRate;
  const limit = options.limit ?? items.length;
  const visible = items.slice(0, limit);

  container.innerHTML = visible.map(item => {
    const pct = Math.max(3, Math.min(100, item.rate / scaleMax * 100));
    const riskClass = item.rate >= 30 ? "danger" : item.rate >= 18 ? "warn" : "";
    return `
      <div class="bar-row">
        <div class="bar-label">${escapeHtml(item.label)}</div>
        <div class="bar-track" aria-label="${escapeHtml(item.label)} attrition rate ${item.rate.toFixed(1)} percent">
          <div class="bar-fill ${riskClass}" style="width:${pct.toFixed(2)}%"></div>
        </div>
        <div class="bar-value">${item.rate.toFixed(1)}% · ${item.attrition}/${item.total}</div>
      </div>
    `;
  }).join("");
}

function segmentStats(rows, label, predicate, interpretation) {
  const subset = rows.filter(predicate);
  return {
    label,
    total: subset.length,
    attrition: subset.filter(isAttrition).length,
    rate: rate(subset),
    interpretation
  };
}

function renderRiskTable(rows) {
  const fullRows = rows.length ? rows : HR_DATA;
  const segments = [
    segmentStats(fullRows, "Overtime employees", r => r.OverTime === "Yes", "Review workload allocation, overtime policy, and manager escalation for recurring high-load employees."),
    segmentStats(fullRows, "Early-tenure employees — 0–2 years", r => Number(r.YearsAtCompany || 0) <= 2, "Strengthen onboarding, mentoring, role clarity, and first-year engagement routines."),
    segmentStats(fullRows, "Employees under 30", r => Number(r.Age || 0) < 30, "Improve career-path visibility, learning opportunities, and early-career retention programs."),
    segmentStats(fullRows, "Low income band — below $3K", r => Number(r.MonthlyIncome || 0) < 3000, "Evaluate pay competitiveness and progression expectations for lower-income employees."),
    segmentStats(fullRows, "Low work-life balance — score 1", r => Number(r.WorkLifeBalance || 0) === 1, "Investigate workload, scheduling flexibility, and team-level burnout risk."),
    segmentStats(fullRows, "Frequent business travel", r => r.BusinessTravel === "Travel_Frequently", "Assess travel burden and provide support for roles with mobility pressure."),
    segmentStats(fullRows, "Sales Representative role", r => r.JobRole === "Sales Representative", "Review target pressure, sales incentive design, coaching, and career mobility."),
    segmentStats(fullRows, "Sales department", r => r.Department === "Sales", "Prioritize sales retention diagnostics because this department often carries higher attrition exposure.")
  ].filter(item => item.total > 0).sort((a, b) => b.rate - a.rate || b.total - a.total);

  $("riskTableBody").innerHTML = segments.map(item => `
    <tr>
      <td><strong>${escapeHtml(item.label)}</strong></td>
      <td>${fmtNumber.format(item.total)}</td>
      <td>${fmtNumber.format(item.attrition)}</td>
      <td><strong>${item.rate.toFixed(1)}%</strong></td>
      <td>${escapeHtml(item.interpretation)}</td>
    </tr>
  `).join("");
}

function updateDashboard() {
  const rows = getFilteredRows();
  const total = rows.length;
  const attritionCount = rows.filter(isAttrition).length;
  const activeCount = total - attritionCount;
  const attritionRate = rate(rows);

  $("kpiEmployees").textContent = fmtNumber.format(total);
  $("kpiAttrition").textContent = fmtNumber.format(attritionCount);
  $("kpiActive").textContent = fmtNumber.format(activeCount);
  $("kpiIncome").textContent = fmtCurrency.format(average(rows, "MonthlyIncome"));
  $("heroAttritionRate").textContent = `${attritionRate.toFixed(1)}%`;

  const overtimeItems = groupBy(rows, "OverTime", { order: ["Yes", "No"] });
  const overtimeYes = overtimeItems.find(item => item.label === "Yes");
  const overtimeNo = overtimeItems.find(item => item.label === "No");
  const jobRoles = groupBy(rows, "JobRole", { minTotal: 10 });
  const tenureItems = groupBy(rows, tenureGroup, { order: ["0–2 years", "3–5 years", "6–10 years", "> 10 years"] });
  const earlyTenure = tenureItems.find(item => item.label === "0–2 years");

  const riskText = overtimeYes && overtimeNo
    ? `Overtime employees show ${overtimeYes.rate.toFixed(1)}% attrition versus ${overtimeNo.rate.toFixed(1)}% among non-overtime employees.`
    : "Overtime risk comparison is limited for this selected segment.";
  $("heroInsight").textContent = `The selected segment includes ${fmtNumber.format(total)} employees with ${attritionRate.toFixed(1)}% attrition. ${riskText} ${jobRoles[0] ? `Highest-risk role: ${jobRoles[0].label} (${jobRoles[0].rate.toFixed(1)}%).` : ""}`;

  if (overtimeYes) {
    $("riskSignal").textContent = `Overtime: ${overtimeYes.rate.toFixed(1)}%`;
    $("riskSignalDesc").textContent = `${overtimeYes.attrition} of ${overtimeYes.total} overtime employees resigned in this selection.`;
  } else {
    $("riskSignal").textContent = "No overtime signal";
    $("riskSignalDesc").textContent = "No overtime segment is available under the current filters.";
  }

  if (jobRoles[0]) {
    $("riskRole").textContent = `${jobRoles[0].label}`;
    $("riskRoleDesc").textContent = `${jobRoles[0].rate.toFixed(1)}% attrition across ${jobRoles[0].total} employees in this role.`;
  } else {
    $("riskRole").textContent = "Limited data";
    $("riskRoleDesc").textContent = "No role has enough employees for a stable comparison under the current filters.";
  }

  if (earlyTenure) {
    $("tenureSignal").textContent = `0–2 years: ${earlyTenure.rate.toFixed(1)}%`;
    $("tenureSignalDesc").textContent = `${earlyTenure.attrition} of ${earlyTenure.total} early-tenure employees resigned.`;
  } else {
    $("tenureSignal").textContent = "No early-tenure data";
    $("tenureSignalDesc").textContent = "No 0–2 year tenure segment is available under the current filters.";
  }

  renderBars("departmentChart", groupBy(rows, "Department"), { scaleTo100: false });
  renderBars("overtimeChart", overtimeItems, { scaleTo100: false });
  renderBars("jobRoleChart", jobRoles, { limit: 8, scaleTo100: false });
  renderBars("ageChart", groupBy(rows, ageGroup, { order: ["< 30", "30–39", "40–49", "50+"] }), { scaleTo100: false });
  renderBars("tenureChart", tenureItems, { scaleTo100: false });
  renderBars("incomeChart", groupBy(rows, incomeGroup, { order: ["< $3K", "$3K–$4.9K", "$5K–$7.9K", "$8K–$11.9K", "$12K+"] }), { scaleTo100: false });
  renderBars("worklifeChart", groupBy(rows, worklifeGroup, { order: ["1 — Low", "2 — Fair", "3 — Good", "4 — Excellent"] }), { scaleTo100: false });
  renderRiskTable(rows);
}

function initFilters() {
  fillSelect("departmentFilter", uniqueValues("Department"), "All Departments");
  fillSelect("jobRoleFilter", uniqueValues("JobRole"), "All Job Roles");
  fillSelect("genderFilter", uniqueValues("Gender"), "All Genders");
  fillSelect("overtimeFilter", uniqueValues("OverTime"), "All Overtime Status");

  $("departmentFilter").addEventListener("change", e => { state.department = e.target.value; updateDashboard(); });
  $("jobRoleFilter").addEventListener("change", e => { state.jobRole = e.target.value; updateDashboard(); });
  $("genderFilter").addEventListener("change", e => { state.gender = e.target.value; updateDashboard(); });
  $("overtimeFilter").addEventListener("change", e => { state.overtime = e.target.value; updateDashboard(); });
  $("resetFiltersBtn").addEventListener("click", () => {
    state.department = state.jobRole = state.gender = state.overtime = "All";
    $("departmentFilter").value = "All";
    $("jobRoleFilter").value = "All";
    $("genderFilter").value = "All";
    $("overtimeFilter").value = "All";
    updateDashboard();
  });
}

document.addEventListener("DOMContentLoaded", () => {
  initFilters();
  updateDashboard();
});
